    17	        var existing = await dbContext.InventoryMovements.SingleOrDefaultAsync(movement => movement.WorkspaceId == workspaceId &&
    18	            movement.IdempotencyKey == idempotencyKey, cancellationToken);
    19	        if (existing is not null) return existing;
    20	
    21	        var warehouseExists = await dbContext.Warehouses.AnyAsync(warehouse => warehouse.Id == warehouseId &&
    22	            warehouse.WorkspaceId == workspaceId && warehouse.ArchivedAtUtc == null, cancellationToken);
    23	        var productExists = await dbContext.Products.AnyAsync(product => product.Id == productId &&
    24	            product.WorkspaceId == workspaceId && product.ArchivedAtUtc == null, cancellationToken);
    25	        if (!warehouseExists || !productExists) return null;
    26	
    27	        var balance = await dbContext.InventoryBalances.SingleOrDefaultAsync(item => item.WorkspaceId == workspaceId &&
    28	            item.WarehouseId == warehouseId && item.ProductId == productId, cancellationToken);
    29	        if (balance is null)
    30	        {
    31	            balance = new InventoryBalance(workspaceId, warehouseId, productId, 0m);
    32	            dbContext.InventoryBalances.Add(balance);
    33	        }
    34	
    35	        balance.Apply(type == InventoryMovementType.Receipt ? quantity : -quantity);
    36	        var movement = new InventoryMovement(movementId, workspaceId, warehouseId, productId, type, quantity, idempotencyKey,
    37	            balance.Quantity, occurredAtUtc);
    38	        dbContext.InventoryMovements.Add(movement);
    39	        return movement;
    40	    }
