     1	using System.Net;
     2	using System.Net.Http.Headers;
     3	using System.Net.Http.Json;
     4	using InventoryFlow.Application.Features.Authentication;
     5	using InventoryFlow.Application.Features.Products;
     6	using InventoryFlow.Application.Features.Purchases;
     7	using InventoryFlow.Application.Features.Suppliers;
     8	using InventoryFlow.Application.Features.Warehouses;
     9	using InventoryFlow.Domain.Entities;
    10	using InventoryFlow.Infrastructure.Persistence;
    11	using Microsoft.AspNetCore.Mvc.Testing;
    12	using Microsoft.EntityFrameworkCore;
    13	using Microsoft.Extensions.DependencyInjection;
    14	
    15	namespace InventoryFlow.IntegrationTests.Api;
    16	
    17	public sealed class PurchaseReceiptEndpointsTests : IClassFixture<AuthenticatedApiFixture>
    18	{
    19	    private readonly AuthenticatedApiFixture _fixture;
    20	    private readonly HttpClient _client;
    21	
    22	    public PurchaseReceiptEndpointsTests(AuthenticatedApiFixture fixture)
    23	    {
    24	        _fixture = fixture;
    25	        _client = fixture.Factory.CreateClient(new WebApplicationFactoryClientOptions { HandleCookies = false });
    26	    }
    27	
    28	    [Fact]
    29	    public async Task Receipt_IsAtomicAndReplayReturnsTheOriginalDocument()
    30	    {
    31	        var session = await RegisterAsync();
    32	        var suffix = Guid.NewGuid().ToString("N");
    33	        var supplier = await PostAsync<SupplierResponse>("/api/suppliers", session.AccessToken, new CreateSupplierRequest($"Supplier {suffix}"));
    34	        var warehouse = await PostAsync<WarehouseResponse>("/api/warehouses", session.AccessToken, new CreateWarehouseRequest($"Warehouse {suffix}"));
    35	        var product = await PostAsync<ProductResponse>("/api/products", session.AccessToken, new CreateProductRequest($"Product {suffix}", $"SKU-{suffix}"));
    36	        var request = new RecordPurchaseReceiptRequest(supplier.Id, warehouse.Id, product.Id, 2.5m, $"receipt-{suffix}");
    37	
    38	        using var first = await SendAsync(HttpMethod.Post, "/api/purchases/receipts", session.AccessToken, request);
    39	        using var replay = await SendAsync(HttpMethod.Post, "/api/purchases/receipts", session.AccessToken, request);
    40	        Assert.Equal(HttpStatusCode.Created, first.StatusCode);
    41	        Assert.Equal(HttpStatusCode.Created, replay.StatusCode);
    42	        var posted = (await first.Content.ReadFromJsonAsync<PurchaseReceiptResponse>())!;
    43	        var replayed = (await replay.Content.ReadFromJsonAsync<PurchaseReceiptResponse>())!;
    44	        Assert.Equal(posted.Id, replayed.Id);
    45	
    46	        await using var scope = _fixture.Factory.Services.CreateAsyncScope();
    47	        var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
    48	        var receipt = await db.PurchaseReceipts.SingleAsync(item => item.Id == posted.Id);
    49	        var movement = await db.InventoryMovements.SingleAsync(item => item.Id == receipt.InventoryMovementId);
    50	        var balance = await db.InventoryBalances.SingleAsync(item => item.WorkspaceId == session.User.Workspace.Id);
    51	        Assert.Equal(InventoryMovementType.Receipt, movement.Type);
    52	        Assert.Equal(2.5m, balance.Quantity);
    53	        Assert.Equal(1, await db.PurchaseReceipts.CountAsync(item => item.WorkspaceId == session.User.Workspace.Id));
    54	        Assert.Equal(1, await db.InventoryMovements.CountAsync(item => item.WorkspaceId == session.User.Workspace.Id));
    55	    }
    56	
    57	    [Fact]
    58	    public async Task Receipt_ConcurrentReplayCreatesOneDocumentAndMovement()
    59	    {
    60	        var session = await RegisterAsync();
    61	        var suffix = Guid.NewGuid().ToString("N");
    62	        var supplier = await PostAsync<SupplierResponse>("/api/suppliers", session.AccessToken, new CreateSupplierRequest($"Supplier {suffix}"));
    63	        var warehouse = await PostAsync<WarehouseResponse>("/api/warehouses", session.AccessToken, new CreateWarehouseRequest($"Warehouse {suffix}"));
    64	        var product = await PostAsync<ProductResponse>("/api/products", session.AccessToken, new CreateProductRequest($"Product {suffix}", $"SKU-{suffix}"));
    65	        var request = new RecordPurchaseReceiptRequest(supplier.Id, warehouse.Id, product.Id, 1m, $"receipt-{suffix}");
    66	
    67	        var responses = await Task.WhenAll(
    68	            SendAsync(HttpMethod.Post, "/api/purchases/receipts", session.AccessToken, request),
    69	            SendAsync(HttpMethod.Post, "/api/purchases/receipts", session.AccessToken, request));
    70	        using var first = responses[0];
    71	        using var second = responses[1];
    72	        Assert.Equal(HttpStatusCode.Created, first.StatusCode);
    73	        Assert.Equal(HttpStatusCode.Created, second.StatusCode);
    74	
    75	        await using var scope = _fixture.Factory.Services.CreateAsyncScope();
    76	        var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
    77	        Assert.Equal(1, await db.PurchaseReceipts.CountAsync(item => item.WorkspaceId == session.User.Workspace.Id));
    78	        Assert.Equal(1, await db.InventoryMovements.CountAsync(item => item.WorkspaceId == session.User.Workspace.Id));
    79	        Assert.Equal(1m, await db.InventoryBalances.Where(item => item.WorkspaceId == session.User.Workspace.Id).Select(item => item.Quantity).SingleAsync());
    80	    }
    81	
    82	    private async Task<T> PostAsync<T>(string path, string token, object content)
    83	    {
    84	        using var response = await SendAsync(HttpMethod.Post, path, token, content);
    85	        Assert.Equal(HttpStatusCode.Created, response.StatusCode);
    86	        return (await response.Content.ReadFromJsonAsync<T>())!;
    87	    }
    88	
    89	    private async Task<AuthenticationResponse> RegisterAsync()
    90	    {
    91	        var suffix = Guid.NewGuid().ToString("N");
    92	        using var response = await _client.PostAsJsonAsync("/api/auth/register", new RegisterUserCommand($"User {suffix}", $"user-{suffix}@example.test", "Password!12345"));
    93	        Assert.Equal(HttpStatusCode.OK, response.StatusCode);
    94	        return (await response.Content.ReadFromJsonAsync<AuthenticationResponse>())!;
    95	    }
    96	
    97	    private async Task<HttpResponseMessage> SendAsync(HttpMethod method, string path, string token, object? content = null)
    98	    {
    99	        using var request = new HttpRequestMessage(method, path);
   100	        request.Headers.Authorization = new AuthenticationHeaderValue("Bearer", token);
   101	        if (content is not null) request.Content = JsonContent.Create(content);
   102	        return await _client.SendAsync(request);
   103	    }
   104	}

