     1	using InventoryFlow.Domain.Entities;
     2	using Microsoft.EntityFrameworkCore;
     3	using Microsoft.EntityFrameworkCore.Metadata.Builders;
     4	
     5	namespace InventoryFlow.Infrastructure.Persistence.Configurations;
     6	
     7	public sealed class PurchaseReceiptConfiguration : IEntityTypeConfiguration<PurchaseReceipt>
     8	{
     9	    public void Configure(EntityTypeBuilder<PurchaseReceipt> builder)
    10	    {
    11	        builder.ToTable("PurchaseReceipts");
    12	        builder.HasKey(receipt => receipt.Id);
    13	        builder.Property(receipt => receipt.Quantity).HasPrecision(18, 4).IsRequired();
    14	        builder.Property(receipt => receipt.IdempotencyKey).HasMaxLength(InventoryMovement.IdempotencyKeyMaxLength).IsRequired();
    15	        builder.Property(receipt => receipt.ReceivedAtUtc).IsRequired();
    16	        builder.HasIndex(receipt => new { receipt.WorkspaceId, receipt.IdempotencyKey }).IsUnique();
    17	        builder.HasIndex(receipt => receipt.InventoryMovementId).IsUnique();
    18	        builder.HasIndex(receipt => new { receipt.WorkspaceId, receipt.ReceivedAtUtc, receipt.Id });
    19	        builder.HasOne<Workspace>().WithMany().HasForeignKey(receipt => receipt.WorkspaceId).OnDelete(DeleteBehavior.Cascade);
    20	        builder.HasOne<Supplier>().WithMany().HasForeignKey(receipt => receipt.SupplierId).OnDelete(DeleteBehavior.Restrict);
    21	        builder.HasOne<Warehouse>().WithMany().HasForeignKey(receipt => receipt.WarehouseId).OnDelete(DeleteBehavior.Restrict);
    22	        builder.HasOne<Product>().WithMany().HasForeignKey(receipt => receipt.ProductId).OnDelete(DeleteBehavior.Restrict);
    23	        builder.HasOne<InventoryMovement>().WithMany().HasForeignKey(receipt => receipt.InventoryMovementId).OnDelete(DeleteBehavior.Restrict);
    24	    }
    25	}

